const email = $json;
const labelsRaw = JSON.parse(email.allGmailLabels || "[]");
const labelsMap = {};
if (Array.isArray(labelsRaw)) {
  for (const label of labelsRaw) labelsMap[label.id] = label.name;
}
let targetWebhookUrl = null;
let targetLabelName = "Unknown";
let embedColor = 10181046;

const webhookUrls = {
  "Internal": "https://discord.com/api/webhooks/1484329239795859587/ZSbwFaCWqUpHcNEY1hCwUpfXxbEw3ml4BcYpSC_Ds4hVUdSkErAjbgTowS4GjbXnk8iz",
  "News": "https://discord.com/api/webhooks/1362473451389976687/o-XY4l7P4Ar6GzQ1ScQoU0s_tMElw8miMBWIMyaWXFEUVTruHYE5EScSrKFyJNp2vN6R",
  "Alerts": "https://discord.com/api/webhooks/1485602784958218290/1U_cPCn0sp0a6c9xm_pa1GXDguIxLEHiwbthmIl1M4fIAQ9nBIoPusTOJ7RHEB5HaHZw",
  "TechNews": "https://discord.com/api/webhooks/1362473170006835431/BPgPQ1b2X3XdMZGvpn_jLhxAlL4T331VSlvimwzaDgm-UOnMdux6ugHFKXJc-K22p-1q",
  "DevNews": "https://discord.com/api/webhooks/1362473344016056594/yjL2PZmqHlnLqw451jGU6HeO-ZIoTwzXxLTd1-2n14SbogKvUm0MEabrHmtzoIw9es0X",
  "BusinessNews": "https://discord.com/api/webhooks/1362473680030011734/h1yI_NpkxUoDfkZClwUMwQzezulcUrhPnMfkh126NS1imos80Ml_8csJXmNR84iF2Df6"
};

const currentLabelIds = email.labelIds || (email.labels ? email.labels.map(l => l.id) : []);
for (const labelId of currentLabelIds) {
  const labelName = labelsMap[labelId] || "";
  if (labelName) {
    targetLabelName = labelName;
    if (labelName.startsWith("@business")) {
      targetWebhookUrl = webhookUrls["BusinessNews"]; embedColor = 3066993; break;
    } else if (labelName === "_news/dev" || labelName === "_tools/dev") {
      targetWebhookUrl = webhookUrls["DevNews"]; embedColor = 1146986; break;
    } else if (labelName === "_news/design" || labelName === "_tools/design") {
      targetWebhookUrl = webhookUrls["News"]; embedColor = 15105570; break;
    } else if (labelName === "_news/AI" || labelName === "_tools/ai" || labelName === "_news/tech") {
      targetWebhookUrl = webhookUrls["TechNews"]; embedColor = 2123412; break;
    } else if (labelName === "_logs" || labelName === "_alerts") {
      targetWebhookUrl = webhookUrls["Alerts"]; embedColor = 15158332; break;
    } else if (labelName.startsWith("@") || labelName.startsWith("_")) {
      targetWebhookUrl = webhookUrls["News"]; break;
    }
  }
}

if (!targetWebhookUrl) {
  if (currentLabelIds.some(id => labelsMap[id] === "INBOX")) {
     targetWebhookUrl = webhookUrls["Internal"];
     targetLabelName = "INBOX";
  } else {
     targetWebhookUrl = webhookUrls["Internal"];
     targetLabelName = "INBOX/Other";
  }
}

let from = email.From || email.from || email.sender || email.Sender || 'Unknown Sender';
let subject = email.Subject || email.subject || 'No Subject';

function getHeader(headers, name) {
  if (!headers) return null;
  if (Array.isArray(headers)) {
    let h = headers.find(h => h.name && h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : null;
  }
  for (let key in headers) {
    if (key.toLowerCase() === name.toLowerCase()) return headers[key];
  }
  return null;
}

if (from === 'Unknown Sender') {
  let f = getHeader(email.payload && email.payload.headers, 'from') || getHeader(email.headers, 'from');
  if (f) from = f;
}
if (subject === 'No Subject') {
  let s = getHeader(email.payload && email.payload.headers, 'subject') || getHeader(email.headers, 'subject');
  if (s) subject = s;
}

function decodeBase64Url(str) {
  if (!str) return '';
  return Buffer.from(str.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
}

function getBodyText(emailObj) {
  if (emailObj.textPlain) return emailObj.textPlain;
  if (emailObj.textHtml) return emailObj.textHtml.replace(/<[^>]*>?/gm, ' ').replace(/&nbsp;/g, ' ');
  let payload = emailObj.payload;
  if (!payload) return '';
  if (payload.mimeType === 'text/plain' && payload.body && payload.body.data) return decodeBase64Url(payload.body.data);
  if (payload.parts && payload.parts.length > 0) {
    let plainPart = payload.parts.find(p => p.mimeType === 'text/plain');
    if (plainPart && plainPart.body && plainPart.body.data) return decodeBase64Url(plainPart.body.data);
    let htmlPart = payload.parts.find(p => p.mimeType === 'text/html');
    if (htmlPart && htmlPart.body && htmlPart.body.data) return decodeBase64Url(htmlPart.body.data).replace(/<[^>]*>?/gm, ' ').replace(/&nbsp;/g, ' ');
  }
  return '';
}

let plainTextBody = getBodyText(email) || email.snippet || 'No body content';
plainTextBody = plainTextBody.replace(/\s+/g, ' ').trim();

const emailLink = 'https://mail.google.com/mail/u/0/#inbox/' + (email.threadId || email.id);
const date = email.internalDate ? new Date(parseInt(email.internalDate)).toLocaleString() : new Date().toLocaleString();

const discordMessage = {
    content: `📨 **New Studio Email** [${targetLabelName}]`,
    embeds: [
      {
        title: subject,
        description: plainTextBody.substring(0, 1500) + (plainTextBody.length > 1500 ? '...' : ''),
        url: emailLink,
        color: embedColor,
        fields: [
          { name: "From", value: from, inline: true },
          { name: "Date", value: date, inline: true }
        ]
      }
    ]
};

return { json: { webhookUrl: targetWebhookUrl, discordMessage: discordMessage, id: email.id } };

